INSERT INTO messages (id, lead_id, direction, body, sent_at) VALUES
  ('aa000001-0000-0000-0000-000000000001', 'b1111111-0000-0000-0000-000000000001', 'inbound',  'Здравствуйте! Видел вас на конференции. Ищем CRM для отдела продаж из 12 человек, посоветуете?', NOW() - INTERVAL '6 days'),
  ('aa000001-0000-0000-0000-000000000002', 'b1111111-0000-0000-0000-000000000001', 'outbound', 'Алексей, добрый день! Да, конечно. Под отдел из 12 человек подойдёт тариф Team. Какой у вас сейчас стек и есть ли требования по интеграциям?', NOW() - INTERVAL '6 days' + INTERVAL '20 min'),
  ('aa000001-0000-0000-0000-000000000003', 'b1111111-0000-0000-0000-000000000001', 'inbound',  'Сейчас всё в Excel и Telegram. Нужна интеграция с телефонией и сайтом.', NOW() - INTERVAL '5 days'),
  ('aa000002-0000-0000-0000-000000000001', 'b1111111-0000-0000-0000-000000000002', 'inbound',  'Добрый день, сколько стоит внедрение и за какой срок реально запуститься?', NOW() - INTERVAL '5 days'),
  ('aa000002-0000-0000-0000-000000000002', 'b1111111-0000-0000-0000-000000000002', 'outbound', 'Марина, здравствуйте! Базовый запуск — 3-5 рабочих дней. Стоимость зависит от числа пользователей, подскажите размер команды?', NOW() - INTERVAL '5 days' + INTERVAL '15 min'),
  ('aa000003-0000-0000-0000-000000000001', 'b1111111-0000-0000-0000-000000000003', 'inbound',  'Нужна интеграция с 1С и телефонией. Бюджет ограничен. Что можете предложить?', NOW() - INTERVAL '8 days'),
  ('aa000003-0000-0000-0000-000000000002', 'b1111111-0000-0000-0000-000000000003', 'outbound', 'Сергей, добрый день! Интеграция с 1С есть из коробки. Давайте созвонимся на 15 минут и подберём оптимальную конфигурацию под бюджет.', NOW() - INTERVAL '7 days'),
  ('aa000005-0000-0000-0000-000000000001', 'b1111111-0000-0000-0000-000000000005', 'inbound',  'Договорились по условиям, готовы стартовать с понедельника. Куда отправить реквизиты?', NOW() - INTERVAL '14 days'),
  ('aa000005-0000-0000-0000-000000000002', 'b1111111-0000-0000-0000-000000000005', 'outbound', 'Павел, отлично! Отправил договор и реквизиты на почту. После оплаты заводим проект и назначаем менеджера внедрения.', NOW() - INTERVAL '13 days'),
  ('aa000006-0000-0000-0000-000000000001', 'b1111111-0000-0000-0000-000000000006', 'inbound',  'Рассматриваем замену текущего решения. Важна аналитика по воронке. Есть ли отчёты?', NOW() - INTERVAL '7 days'),
  ('aa000007-0000-0000-0000-000000000001', 'b1111111-0000-0000-0000-000000000007', 'inbound',  'Привет! А с какими мессенджерами вы интегрируетесь, кроме телеги?', NOW() - INTERVAL '4 days'),
  ('aa000007-0000-0000-0000-000000000002', 'b1111111-0000-0000-0000-000000000007', 'outbound', 'Игорь, привет! Telegram, WhatsApp и Email в одном инбоксе. Что для вас в приоритете?', NOW() - INTERVAL '4 days' + INTERVAL '10 min')
ON CONFLICT (id) DO NOTHING;

