INSERT INTO outbound_messages (id, prospect_id, sequence_id, step_order, channel, body, status, scheduled_at, sent_at, opened_at, replied_at, created_at) VALUES
  ('f6000001-0000-0000-0000-000000000001', 'a2222222-0000-0000-0000-000000000001', 'c3333333-0000-0000-0000-000000000001', 1, 'email',      'Артур, здравствуйте! Помогаем SaaS-командам собирать все заявки из Telegram, Email и сайта в один инбокс с AI-квалификацией. У клиентов из вашей ниши время ответа сократилось в 4 раза. Открыты к 15-минутному звонку на след. неделе?', 'sent',     NOW() - INTERVAL '24 days', NOW() - INTERVAL '24 days', NOW() - INTERVAL '24 days' + INTERVAL '3 hours', NOW() - INTERVAL '23 days', NOW() - INTERVAL '24 days'),
  ('f6000001-0000-0000-0000-000000000002', 'a2222222-0000-0000-0000-000000000001', 'c3333333-0000-0000-0000-000000000001', 2, 'telegram',   'Артур, дополню по прошлому письму: вот короткий кейс CloudMetrics-подобной команды. Какой у вас сейчас инструмент для заявок?', 'sent',     NOW() - INTERVAL '21 days', NOW() - INTERVAL '21 days', NOW() - INTERVAL '21 days' + INTERVAL '1 hour', NULL,                       NOW() - INTERVAL '21 days'),
