-- ============ 6. audit_log (~110 строк за 30 дней — наполняет дашборд стоимости) ============
DELETE FROM audit_log WHERE user_id = :demo;
INSERT INTO audit_log (user_id, lead_id, prospect_id, request_type, provider, model,
    input_tokens, output_tokens, total_tokens, cost_usd_micro, latency_ms, status, created_at)
SELECT
    :demo,
    CASE WHEN i % 3 = 0 THEN (ARRAY[
        'b1111111-0000-0000-0000-000000000001','b1111111-0000-0000-0000-000000000002',
        'b1111111-0000-0000-0000-000000000003','b1111111-0000-0000-0000-000000000005',
        'b1111111-0000-0000-0000-000000000006','b1111111-0000-0000-0000-000000000007'
    ]::uuid[])[(i % 6) + 1] ELSE NULL END,
    CASE WHEN i % 3 = 1 THEN (ARRAY[
        'a2222222-0000-0000-0000-000000000001','a2222222-0000-0000-0000-000000000002',
        'a2222222-0000-0000-0000-000000000005','a2222222-0000-0000-0000-000000000006',
        'a2222222-0000-0000-0000-000000000010'
    ]::uuid[])[(i % 5) + 1] ELSE NULL END,
    (ARRAY['qualification','draft_reply','cold_message','telegram_message','followup','style_check'])[(i % 6) + 1],
    (ARRAY['openai','anthropic','openai','ollama'])[(i % 4) + 1],
    (ARRAY['gpt-4o-mini','claude-haiku-4-5','gpt-4o','gemma3:4b'])[(i % 4) + 1],
    inp, outp, inp + outp,
    -- cost по модели (micro-USD): ollama = 0
    CASE (i % 4)
        WHEN 0 THEN (inp * 0.15 + outp * 0.60)::bigint   -- gpt-4o-mini
        WHEN 1 THEN (inp * 0.80 + outp * 4.00)::bigint   -- claude-haiku
        WHEN 2 THEN (inp * 2.50 + outp * 10.00)::bigint  -- gpt-4o
        ELSE 0
    END,
    300 + (i * 53) % 2200,
    'success',
    NOW() - ((i % 30) || ' days')::interval - ((i * 7 % 24) || ' hours')::interval
FROM (
    SELECT i, 500 + (i * 137) % 2000 AS inp, 150 + (i * 59) % 700 AS outp
    FROM generate_series(1, 110) AS g(i)
) s;

COMMIT;
